@* Reusable message/reply input with textarea and submit button *@

<div class="message-input">
    <textarea class="message-input__textarea"
              rows="2"
              placeholder="@Placeholder"
              @bind="text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown" />
    <button class="message-input__button"
            disabled="@(string.IsNullOrWhiteSpace(text) || isSending)"
            @onclick="Submit">
        @ButtonLabel
    </button>
</div>

@code {
    private string text = string.Empty;
    private bool isSending;

    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSubmit { get; set; }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(text) || isSending) return;

        isSending = true;
        try
        {
            var message = text.Trim();
            text = string.Empty;
            await OnSubmit.InvokeAsync(message);
        }
        finally
        {
            isSending = false;
        }
    }
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input__textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 0.5rem 0.75rem;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input__textarea:focus {
    border-color: #5865f2;
}

.message-input__button {
    align-self: flex-end;
    padding: 0.5rem 1.25rem;
    background: #5865f2;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.message-input__button:hover:not(:disabled) {
    background: #4752c4;
}

.message-input__button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@* Single message: author, time, content, reactions, hover actions, thread link *@

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="OnMouseLeave">
    <div class="message-item__header">
        <span class="message-item__author">@Message.Author</span>
        <span class="message-item__time">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-item__content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-item__reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                        @onclick="() => OnReact.InvokeAsync(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="message-item__thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
            &middot; last @FormatRelativeTime(ThreadSummary.LastReplyAt)
        </button>
    }

    @if (showActions)
    {
        <div class="message-item__actions">
            <button class="action-btn" title="Reply" @onclick="() => OnOpenThread.InvokeAsync()">💬</button>
            <button class="action-btn" title="React" @onclick="ToggleEmojiPicker">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="message-item__emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-pick" @onclick="() => PickEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f2f3f5;
}

.message-item__header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.message-item__author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-item__time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-item__content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-item__reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    font-size: 0.8rem;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f0f0f0;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dfe1e6;
}

.message-item__thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    padding: 0;
    font-size: 0.8rem;
    color: #5865f2;
    background: none;
    border: none;
    cursor: pointer;
    font-weight: 600;
}

.message-item__thread-link:hover {
    text-decoration: underline;
}

.message-item__actions {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.15rem 0.25rem;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #e8e8e8;
}

.message-item__emoji-picker {
    position: absolute;
    top: -2.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 0.3rem 0.4rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-pick {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.2rem;
    padding: 0.15rem 0.3rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-pick:hover {
    background: #f0f0f0;
}

@* Single channel row: #name, description snippet, unread badge *@

<button class="channel-item @(IsActive ? "channel-item--active" : "")"
        @onclick="OnClick">
    <div class="channel-item__top">
        <span class="channel-item__name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="channel-item__badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <span class="channel-item__desc">@Truncate(Channel.Description, 40)</span>
    }
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private static string Truncate(string value, int maxLength) =>
        value.Length <= maxLength ? value : value[..maxLength] + "…";
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    padding: 0.5rem 0.75rem;
    border: none;
    background: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.1s;
}

.channel-item:hover {
    background: #3a3c43;
}

.channel-item--active {
    background: #42454d;
}

.channel-item__top {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-item__name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #dcddde;
}

.channel-item--active .channel-item__name {
    color: #fff;
}

.channel-item__badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.4rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
}

.channel-item__desc {
    display: block;
    font-size: 0.75rem;
    color: #8e9297;
    margin-top: 0.1rem;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

