toolArgs.file_text:
@* Single message: author, time, content, reactions, hover actions, thread link *@

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="OnMouseLeave">
    <div class="message-item__header">
        <span class="message-item__author">@Message.Author</span>
        <span class="message-item__time">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-item__content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-item__reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                        @onclick="() => OnReact.InvokeAsync(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="message-item__thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
            &middot; last @FormatRelativeTime(ThreadSummary.LastReplyAt)
        </button>
    }

    @if (showActions)
    {
        <div class="message-item__actions">
            <button class="action-btn" title="Reply" @onclick="() => OnOpenThread.InvokeAsync()">💬</button>
            <button class="action-btn" title="React" @onclick="ToggleEmojiPicker">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="message-item__emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-pick" @onclick="() => PickEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

