toolArgs.file_text:
.message-item {
    position: relative;
    padding: 0.5rem 0.75rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f2f3f5;
}

.message-item__header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.message-item__author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-item__time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-item__content {
    font-size: 0.9rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-item__reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    font-size: 0.8rem;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    background: #f0f0f0;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dfe1e6;
}

.message-item__thread-link {
    display: inline-block;
    margin-top: 0.3rem;
    padding: 0;
    font-size: 0.8rem;
    color: #5865f2;
    background: none;
    border: none;
    cursor: pointer;
    font-weight: 600;
}

.message-item__thread-link:hover {
    text-decoration: underline;
}

.message-item__actions {
    position: absolute;
    top: -0.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.15rem 0.25rem;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
}

.action-btn {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    padding: 0.2rem 0.35rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #e8e8e8;
}

.message-item__emoji-picker {
    position: absolute;
    top: -2.5rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 0.3rem 0.4rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 10;
}

.emoji-pick {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.2rem;
    padding: 0.15rem 0.3rem;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-pick:hover {
    background: #f0f0f0;
}

