arguments.file_text:
@* Left sidebar: channel list with active highlight *@

<nav class="channel-sidebar">
    <h2 class="channel-sidebar__title">Channels</h2>
    <div class="channel-sidebar__list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    background: #2f3136;
    color: #dcddde;
    overflow: hidden;
}

.channel-sidebar__title {
    padding: 0.9rem 0.75rem;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    border-bottom: 1px solid #26282c;
    flex-shrink: 0;
}

.channel-sidebar__list {
    flex: 1;
    overflow-y: auto;
    padding: 0.35rem 0.4rem;
}

@* Main message area: channel header, scrollable messages, input *@
@using System.Collections.Generic

<div class="message-area">
    <header class="message-area__header">
        <h2 class="message-area__channel-name"># @ChannelName</h2>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="message-area__channel-desc">@ChannelDescription</span>
        }
    </header>

    <div class="message-area__messages" @onscroll="HandleScroll" @ref="scrollContainer">
        @if (IsLoadingMore)
        {
            <div class="message-area__loading">Loading older messages…</div>
        }

        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadSummary="GetThreadSummary(msg.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                         OnReact="emoji => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonLabel="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    private ElementReference scrollContainer;

    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string? ChannelDescription { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    [Inject] private IJSRuntime JS { get; set; } = default!;

    private ThreadSummary? GetThreadSummary(int messageId) =>
        ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval",
            $"document.querySelector('[_bl_{scrollContainer.Id}]')?.scrollTop ?? 1");
        if (scrollTop < 1 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.message-area__header {
    display: flex;
    align-items: baseline;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.message-area__channel-name {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.message-area__channel-desc {
    font-size: 0.85rem;
    color: #72767d;
}

.message-area__messages {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
}

.message-area__loading {
    text-align: center;
    padding: 0.5rem;
    font-size: 0.85rem;
    color: #72767d;
}

@* Right panel: thread view with original message, replies, reply input *@

<aside class="thread-panel">
    <header class="thread-panel__header">
        <h3 class="thread-panel__title">Thread</h3>
        <button class="thread-panel__close" @onclick="OnClose" title="Close thread">&times;</button>
    </header>

    @if (RootMessage is not null)
    {
        <div class="thread-panel__root">
            <MessageItem Message="RootMessage" />
        </div>

        <div class="thread-panel__divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-panel__replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             OnReact="emoji => OnReactToReply.InvokeAsync((reply.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    }
</aside>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactToReply { get; set; }
}

